<script lang="ts">
  import "../app.css";
  // import favicon from "$lib/assets/favicon.svg";
  import "@fontsource-variable/inter";
  import { page } from "$app/state";
  import "default-passive-events";
  import { env } from "$env/dynamic/public";
  import { setupConvex } from "convex-svelte";

  let { children } = $props();

  setupConvex(env.PUBLIC_CONVEX_URL);

  import { useQuery } from "convex-svelte";
  import { api } from "../../dashboard/src/convex/_generated/api";

  const oddinHost = env.PUBLIC_ODDIN_HOST;

  const query = useQuery(api.site.get);

  const canonicalUrl = $derived(
    (() => {
      const protocol = page.url.protocol;
      const origin = page.url.host;
      const path = page.url.pathname;

      const base = `${protocol}//${origin}`;

      if (path === "/") return base;
      if (/^\/[^/]+$/.test(path)) return base + path;
      return base + path;
    })(),
  );

  function detectImageTypeFromBase64(base64: string): string {
    const firstChar = base64.trim();
    switch (firstChar) {
      case "/":
        return "image/jpeg"; // JPEG
      case "i":
        return "image/png"; // PNG
      case "A":
        return "image/ico"; // ICO
      case "P":
        return "image/svg+xml"; // SVG
      case "U":
        return "image/webp"; // WEBP
      case "T":
        return "image/tiff"; // TIFF
      case "Q":
        return "image/bmp"; // BMP
      case "AAAA":
        return "image/avif"; // AVIF
      default:
        return ""; // Default fallback
    }
  }

  let base64 =
    "";

  let sites = $derived(
    oddinHost === "beep.oddinpay.com"
      ? (query.data ?? []).map((site) => {
          const b64 = site.image ?? base64;
          return {
            ...site,
            b64,
          };
        })
      : [{ b64: base64 }],
  );

  let activeFavicon = $state("");

  $effect(() => {
    sites.forEach((site) => {
      let b64 = site.b64;
      const type = detectImageTypeFromBase64(b64);
      if (type === "image/svg+xml" && b64.startsWith("PHN2Zy")) {
        activeFavicon = `data:image/svg+xml;utf8,${encodeURIComponent(b64)}`;
      } else {
        activeFavicon = `data:${type};base64,${b64}`;
      }
    });
  });
</script>

<svelte:head>
  <link rel="icon" href={activeFavicon} />

  <!-- Canonical URL -->
  <link rel="canonical" href={canonicalUrl} />
</svelte:head>

{@render children?.()}
